insert into public.cities (id, name, name_en, region, status, founded_year, founded_year_en, population_before_1948, short_desc, short_desc_en, description, description_en, geography, geography_en, history, history_en, natives, natives_en, highlights, highlights_en, naming, naming_en, zionist_name, zionist_name_en, brief, brief_en, image, gallery, date, date_en, sort_order) values
  ('al-quds', 'مدينة القدس', 'Jerusalem', 'jerusalem', 'occupied', 'الألف الثالث ق.م', '3rd millennium BCE', '165,000', 'مدينة القدس هي واحدة من أقدم وأقدس المدن في العالم.', 'Jerusalem is one of the oldest and holiest cities in the world.', 'القدس هي إحدى أقدم مدن العالم وأكثرها أهميةً تاريخيًا ودينيًا. تقع في قلب فلسطين. تُعد مركزًا حضاريًا وثقافيًا ودينيًا فريدًا. تحتضن العديد من المعالم التاريخية المقدسة للمسلمين والمسيحيين واليهود.', 'Jerusalem is one of the oldest and most historically and religiously significant cities in the world. Located in the heart of Palestine, it is a unique civilizational, cultural, and religious center, home to many holy sites sacred to Muslims, Christians, and Jews.', 'تقع مدينة القدس في الجزء الأوسط من فلسطين التاريخية، على سلسلة من الهضاب الجبلية بين البحر الأبيض المتوسط والبحر الميت. ترتفع عن سطح البحر بحوالي 750 مترًا.', 'Jerusalem lies in the central part of historic Palestine, on a chain of mountainous plateaus between the Mediterranean Sea and the Dead Sea, at an elevation of about 750 meters above sea level.', 'تُعد القدس من أقدم المدن المأهولة في العالم، إذ يعود تاريخها إلى أكثر من خمسة آلاف عام. شهدت المدينة تعاقب العديد من الحضارات، منها الكنعانية واليبوسية والآشورية والبابلية والفارسية واليونانية والرومانية والإسلامية والعثمانية.', 'Jerusalem is among the oldest continuously inhabited cities in the world, with a history spanning more than five thousand years. It witnessed the succession of Canaanite, Jebusite, Assyrian, Babylonian, Persian, Greek, Roman, Islamic, and Ottoman civilizations.', 'يُعتبر اليبوسيون، وهم إحدى القبائل الكنعانية العربية القديمة، السكان الأصليين لمدينة القدس. وقد أسسوا المدينة في الألف الثالث قبل الميلاد وأطلقوا عليها اسم "يبوس".', 'The Jebusites, one of the ancient Arab Canaanite tribes, are considered the indigenous inhabitants of Jerusalem. They founded the city in the third millennium BCE and named it "Jebus".', ARRAY['تضم المسجد الأقصى المبارك وقبة الصخرة المشرفة.','تحتوي على كنيسة القيامة، أحد أهم المواقع المقدسة لدى المسيحيين.','تُعد مركزًا تاريخيًا وثقافيًا يضم العديد من المتاحف والمعالم الأثرية.','تتميز بطراز معماري فريد يجمع بين الحضارات المختلفة.','تُعتبر من أهم الوجهات الدينية والسياحية في العالم.']::text[], ARRAY['Home to the blessed Al-Aqsa Mosque and the Dome of the Rock.','Contains the Church of the Holy Sepulchre, one of the holiest Christian sites.','A historic and cultural center with many museums and archaeological landmarks.','Features unique architecture blending many civilizations.','Considered one of the world''s foremost religious and tourist destinations.']::text[], 'يرجع اسم القدس إلى كلمة "القداسة" أو "المدينة المقدسة"، وذلك لما تتمتع به من مكانة دينية عظيمة لدى أتباع الديانات السماوية.', 'The name Al-Quds derives from "holiness" or "the holy city", reflecting its sacred status to followers of the Abrahamic faiths.', 'تُطلق السلطات الإسرائيلية والمصادر العبرية على المدينة اسم "يروشليم / ‎ירושלים".', 'Israeli authorities and Hebrew sources call the city "Yerushalayim / ‎ירושלים".', 'القدس هي العاصمة التاريخية لفلسطين وأحد أقدس مدن العالم.', 'Jerusalem is the historic capital of Palestine and one of the holiest cities in the world.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d8/Dome_of_the_Rock_Temple_Mount.jpg/1280px-Dome_of_the_Rock_Temple_Mount.jpg', ARRAY['https://upload.wikimedia.org/wikipedia/commons/thumb/d/d8/Dome_of_the_Rock_Temple_Mount.jpg/640px-Dome_of_the_Rock_Temple_Mount.jpg','https://upload.wikimedia.org/wikipedia/commons/thumb/8/8c/Church_of_the_Holy_Sepulchre_2010.jpg/640px-Church_of_the_Holy_Sepulchre_2010.jpg','https://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/Jerusalem_Western_Wall_BW_3.JPG/640px-Jerusalem_Western_Wall_BW_3.JPG']::text[], '2 يونيو 2026', 'June 2, 2026', 0),
  ('al-khalil', 'مدينة الخليل', 'Hebron', 'west_bank', 'partially_destroyed', '3500 ق.م', '3500 BCE', '24,000', 'هي أكبر مدن الضفة الغربية من حيث المساحة وعدد السكان.', 'The largest city in the West Bank by area and population.', 'الخليل من أقدم المدن الفلسطينية المأهولة، تشتهر بأسواقها التراثية وحرفها اليدوية كصناعة الزجاج والخزف، وتحتضن الحرم الإبراهيمي الشريف.', 'Hebron is one of the oldest inhabited Palestinian cities, known for its heritage markets and handicrafts such as glassmaking and ceramics, and home to the Ibrahimi Mosque.', 'تقع الخليل في الجزء الجنوبي من الضفة الغربية، على ارتفاع نحو 930 مترًا فوق سطح البحر، مما يجعلها من أعلى المدن الفلسطينية ارتفاعًا.', 'Hebron lies in the southern West Bank at an elevation of about 930 meters above sea level, making it one of the highest Palestinian cities.', 'يعود تاريخ الخليل لأكثر من 5500 عام. سُكنت من قِبَل الكنعانيين، وارتبط اسمها بسيدنا إبراهيم الخليل عليه السلام.', 'Hebron''s history spans more than 5,500 years. It was inhabited by the Canaanites, and its name is associated with the Prophet Abraham.', 'السكان الأصليون من الكنعانيين، ولا يزال الفلسطينيون يشكّلون النسيج السكاني الرئيسي للمدينة.', 'The original inhabitants were Canaanites, and Palestinians remain the main population of the city.', ARRAY['الحرم الإبراهيمي الشريف.','البلدة القديمة وأسواقها التراثية.','صناعة الزجاج الخليلي والخزف.','كروم العنب والتين المشهورة.']::text[], ARRAY['The Ibrahimi Mosque.','The Old City and its heritage markets.','Hebron glassmaking and ceramics.','Famous grape and fig orchards.']::text[], 'سُمّيت بالخليل نسبةً إلى نبي الله إبراهيم الخليل عليه السلام.', 'Named Al-Khalil after the Prophet Abraham, "Khalil Allah" (Friend of God).', 'تُسمّى في المصادر العبرية باسم "حيفرون / ‎חברון".', 'Called "Hevron / ‎חברון" in Hebrew sources.', 'الخليل مدينة الحرم الإبراهيمي والتراث الفلسطيني الأصيل.', 'Hebron: the city of the Ibrahimi Mosque and authentic Palestinian heritage.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9b/Hebron_old_city_2009.jpg/1280px-Hebron_old_city_2009.jpg', ARRAY[]::text[], '2 يونيو 2026', 'June 2, 2026', 1),
  ('ghazza', 'مدينة غزة', 'Gaza', 'gaza', 'partially_destroyed', '3000 ق.م', '3000 BCE', '80,000', 'مدينة فلسطينية ساحلية عريقة تُعد من أقدم مدن العالم.', 'An ancient Palestinian coastal city, among the oldest in the world.', 'غزة مدينة فلسطينية ساحلية تقع على البحر الأبيض المتوسط، تُعدّ من أقدم المدن المأهولة في العالم، ومركزًا تجاريًا وثقافيًا للشعب الفلسطيني.', 'Gaza is a Palestinian coastal city on the Mediterranean, one of the oldest inhabited cities in the world, and a commercial and cultural center for the Palestinian people.', 'تقع على الساحل الجنوبي الغربي لفلسطين، تطل على البحر الأبيض المتوسط، وتمتد على شريط ساحلي بطول 41 كيلومترًا.', 'Located on Palestine''s southwestern coast, Gaza overlooks the Mediterranean and stretches along a 41-kilometer coastline.', 'تاريخها يمتد لأكثر من 4000 سنة. مرّت بها حضارات الكنعانيين والفلستينيين والمصريين والرومان والعرب المسلمين والعثمانيين.', 'Its history spans more than 4,000 years, with successive Canaanite, Philistine, Egyptian, Roman, Arab Muslim, and Ottoman civilizations.', 'السكان الأصليون من الكنعانيين والفلستينيين القدماء، ويُشكّل الفلسطينيون اليوم سكانها الكاملين.', 'The original inhabitants were ancient Canaanites and Philistines; today the population is entirely Palestinian.', ARRAY['ميناء غزة التاريخي.','الجامع العمري الكبير.','كنيسة القديس برفيريوس من أقدم الكنائس في العالم.','البلدة القديمة وأسواقها التراثية.']::text[], ARRAY['The historic Port of Gaza.','The Great Omari Mosque.','The Church of Saint Porphyrius, one of the world''s oldest churches.','The Old City and its heritage markets.']::text[], 'اسمها مشتق من الكلمة الكنعانية "هزاتي" بمعنى القوية، وعُرفت تاريخيًا بـ"غزة هاشم".', 'Its name derives from the Canaanite "Hazzati" meaning "the strong one"; historically known as "Gaza of Hashim".', 'تُسمّى في المصادر العبرية "عزة / ‎עזה".', 'Called "Azza / ‎עזה" in Hebrew sources.', 'غزة هاشم، مدينة الصمود الفلسطيني، وعاصمة الإرادة على ساحل المتوسط.', 'Gaza of Hashim: city of Palestinian steadfastness, the capital of willpower on the Mediterranean coast.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/36/Gaza_beach.jpg/1280px-Gaza_beach.jpg', ARRAY[]::text[], '2 يونيو 2026', 'June 2, 2026', 2),
  ('nablus', 'مدينة نابلس', 'Nablus', 'west_bank', 'existing', '72م', '72 CE', '23,250', 'إحدى أقدم المدن الفلسطينية، تقع بين جبلي عيبال وجرزيم.', 'One of the oldest Palestinian cities, set between Mounts Ebal and Gerizim.', 'نابلس من أعرق المدن الفلسطينية، تجمع بين التاريخ والطبيعة، وتشتهر بصناعة الصابون والكنافة النابلسية الشهيرة عالميًا.', 'Nablus is one of Palestine''s most distinguished cities, combining history and nature, and famous for its soap industry and world-renowned knafeh.', 'تقع في شمال الضفة الغربية بين جبلي عيبال وجرزيم، وترتفع نحو 550 مترًا عن سطح البحر.', 'Located in the northern West Bank between Mounts Ebal and Gerizim, at about 550 meters above sea level.', 'أسّسها الرومان عام 72م باسم "نيابوليس" أي المدينة الجديدة، وقبلها كانت تُعرف بمدينة شكيم الكنعانية.', 'Founded by the Romans in 72 CE as "Neapolis" (new city); previously known as the Canaanite city of Shechem.', 'سكانها من العرب الفلسطينيين وامتداد للكنعانيين القدماء.', 'Its population consists of Arab Palestinians, descendants of the ancient Canaanites.', ARRAY['البلدة القديمة وحاراتها التاريخية.','صناعة الصابون النابلسي التراثي.','الكنافة النابلسية.','بئر يعقوب التاريخي.']::text[], ARRAY['The Old City and its historic quarters.','Traditional Nabulsi soap industry.','Nabulsi knafeh dessert.','The historic Jacob''s Well.']::text[], 'من الاسم الروماني "نيابوليس" أي المدينة الجديدة.', 'From the Roman name "Neapolis", meaning "the new city".', 'تُسمّى عبريًا "شخيم / ‎שכם".', 'Called "Shechem / ‎שכם" in Hebrew.', 'نابلس عاصمة جبل النار، مدينة الصابون والكنافة والصمود.', 'Nablus, the capital of the Mountain of Fire — the city of soap, knafeh, and steadfastness.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3f/Nablus_City2.jpg/1280px-Nablus_City2.jpg', ARRAY[]::text[], '2 يونيو 2026', 'June 2, 2026', 3),
  ('haifa', 'مدينة حيفا', 'Haifa', '48_territories', 'occupied', 'القرن الثالث ق.م', '3rd century BCE', '75,000', 'مدينة فلسطينية ساحلية تقع على جبل الكرمل المطل على البحر.', 'A Palestinian coastal city on Mount Carmel overlooking the sea.', 'حيفا من أجمل المدن الفلسطينية الساحلية، تجمع بين الجبل والبحر، وتشتهر بميناءها الذي يُعد من أهم موانئ شرق المتوسط.', 'Haifa is one of the most beautiful Palestinian coastal cities, combining mountain and sea, and known for its port — one of the most important in the eastern Mediterranean.', 'تقع على ساحل البحر الأبيض المتوسط شمال فلسطين، عند سفح جبل الكرمل.', 'Located on the Mediterranean coast of northern Palestine, at the foot of Mount Carmel.', 'مدينة كنعانية قديمة، ازدهرت في العصور المختلفة وتعرّضت للتهجير عام 1948.', 'An ancient Canaanite city that flourished through the ages and was depopulated in 1948.', 'كان أغلب سكانها من الفلسطينيين قبل النكبة عام 1948.', 'Most of its inhabitants were Palestinians before the 1948 Nakba.', ARRAY['جبل الكرمل.','ميناء حيفا.','المدينة القديمة.','الحدائق البهائية.']::text[], ARRAY['Mount Carmel.','Port of Haifa.','The Old City.','The Bahá''í Gardens.']::text[], 'من جذر سامي يعني "الشاطئ الجميل" أو "المرفأ".', 'From a Semitic root meaning "the beautiful shore" or "harbor".', 'تحتفظ بنفس الاسم "حيفا / ‎חיפה".', 'Retains the same name "Haifa / ‎חיפה".', 'حيفا عروس الكرمل، مدينة البحر والجبل الفلسطيني المهجّر.', 'Haifa, the bride of Carmel — the depopulated Palestinian city of sea and mountain.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/1b/Haifa_view_BW_2010-09-08_03.JPG/1280px-Haifa_view_BW_2010-09-08_03.JPG', ARRAY[]::text[], '2 يونيو 2026', 'June 2, 2026', 4),
  ('yaffa', 'مدينة يافا', 'Jaffa', '48_territories', 'occupied', '1800 ق.م', '1800 BCE', '100,000', 'مدينة فلسطينية عريقة على ساحل البحر المتوسط، اشتهرت ببرتقالها.', 'An ancient Palestinian Mediterranean coastal city famous for its oranges.', 'يافا عروس البحر، من أقدم الموانئ في العالم، وعُرفت ببرتقالها الشهير عالميًا قبل النكبة.', 'Jaffa, the bride of the sea — among the oldest ports in the world, world-famous for its oranges before the Nakba.', 'تقع على الساحل الفلسطيني المتوسطي جنوب تل أبيب.', 'Located on the Palestinian Mediterranean coast south of Tel Aviv.', 'أُسّست قبل أكثر من 4000 عام، وكانت ميناءً تجاريًا عالميًا.', 'Founded over 4,000 years ago and was a global commercial port.', 'كان سكانها فلسطينيين، هُجّر معظمهم عام 1948.', 'Its inhabitants were Palestinians, most of whom were displaced in 1948.', ARRAY['ميناء يافا.','البلدة القديمة.','برج الساعة.','برتقال يافا الشهير.']::text[], ARRAY['Port of Jaffa.','The Old City.','The Clock Tower.','The famous Jaffa oranges.']::text[], 'من الاسم الكنعاني "يافي" أي الجميل.', 'From the Canaanite name "Yafi" meaning "the beautiful".', 'تُسمّى عبريًا "يافو / ‎יפו".', 'Called "Yafo / ‎יפו" in Hebrew.', 'يافا عروس البحر وميناء فلسطين التاريخي.', 'Jaffa, the bride of the sea and Palestine''s historic port.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/85/Jaffa_old_town.jpg/1280px-Jaffa_old_town.jpg', ARRAY[]::text[], '2 يونيو 2026', 'June 2, 2026', 5),
  ('salfit', 'مدينة سلفيت', 'Salfit', 'west_bank', 'existing', 'القرن السابع', '7th century', NULL, 'مدينة فلسطينية تقع في شمال الضفة الغربية، تشتهر بطبيعتها.', 'A Palestinian city in the northern West Bank, known for its natural beauty.', 'سلفيت مدينة جبلية فلسطينية في وسط الضفة الغربية، تشتهر بزراعة الزيتون.', 'Salfit is a Palestinian mountain city in the central West Bank, famous for olive cultivation.', 'تقع في وسط الضفة الغربية بين نابلس ورام الله.', 'Located in the central West Bank between Nablus and Ramallah.', 'مدينة قديمة سكنها الكنعانيون والرومان.', 'An ancient city inhabited by Canaanites and Romans.', 'سكانها من الفلسطينيين.', 'Its inhabitants are Palestinians.', ARRAY['كرومة الزيتون.','وادي قانا الطبيعي.','البلدة القديمة.']::text[], ARRAY['Olive groves.','The natural Wadi Qana.','The Old City.']::text[], 'اسم يعود لجذور كنعانية بمعنى السلة أو الجبل.', 'A name of Canaanite roots meaning "basket" or "mountain".', 'تستخدم نفس الاسم في المصادر العبرية.', 'The same name is used in Hebrew sources.', 'سلفيت مدينة الزيتون والطبيعة الجبلية الفلسطينية.', 'Salfit, the Palestinian city of olives and mountain nature.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4d/Salfit2.jpg/1280px-Salfit2.jpg', ARRAY[]::text[], '2 يونيو 2026', 'June 2, 2026', 6),
  ('ramallah', 'مدينة رام الله', 'Ramallah', 'west_bank', 'existing', 'القرن السادس عشر', '16th century', '5,000', 'مدينة فلسطينية حديثة نسبيًا تُعد مركزًا إداريًا وثقافيًا مهمًا.', 'A relatively modern Palestinian city, an important administrative and cultural center.', 'رام الله مركز ثقافي وإداري للسلطة الفلسطينية، تجمع بين الأصالة والحداثة.', 'Ramallah is a cultural and administrative center for the Palestinian Authority, blending authenticity and modernity.', 'تقع في وسط الضفة الغربية شمال القدس بنحو 15 كيلومترًا.', 'Located in the central West Bank, about 15 kilometers north of Jerusalem.', 'أسّسها المسيحيون الفلسطينيون في القرن السادس عشر.', 'Founded by Palestinian Christians in the 16th century.', 'خليط من المسلمين والمسيحيين الفلسطينيين.', 'A mix of Palestinian Muslims and Christians.', ARRAY['مقام ياسر عرفات.','البلدة القديمة.','مهرجانات ثقافية متعددة.']::text[], ARRAY['The Yasser Arafat Mausoleum.','The Old City.','Numerous cultural festivals.']::text[], 'من "رام" بمعنى المرتفع، و"الله" دلالة على القداسة.', 'From "Ram" meaning "high" and "Allah" denoting sanctity.', 'تستخدم نفس الاسم.', 'The same name is used.', 'رام الله العاصمة المؤقتة وقلب فلسطين الثقافي.', 'Ramallah, the interim capital and cultural heart of Palestine.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3b/Ramallah_centre.jpg/1280px-Ramallah_centre.jpg', ARRAY[]::text[], '2 يونيو 2026', 'June 2, 2026', 7),
  ('bisan', 'مدينة بيسان', 'Bisan', '48_territories', 'destroyed', '6000 ق.م', '6000 BCE', '5,540', 'مدينة فلسطينية تاريخية تقع في الأغوار الشمالية، وعُرفت بمعالمها.', 'A historic Palestinian city in the northern Jordan Valley, known for its landmarks.', 'بيسان من أقدم المدن الفلسطينية، تقع في غور الأردن وتشتهر بآثارها الرومانية.', 'Bisan is one of the oldest Palestinian cities, located in the Jordan Valley and famous for its Roman ruins.', 'تقع في الأغوار الشمالية لفلسطين.', 'Located in the northern Jordan Valley of Palestine.', 'مدينة كنعانية قديمة عمرها أكثر من 6000 سنة، هُجّرت عام 1948.', 'An ancient Canaanite city more than 6,000 years old, depopulated in 1948.', 'كان سكانها من الفلسطينيين قبل النكبة.', 'Its inhabitants were Palestinians before the Nakba.', ARRAY['المدرج الروماني.','آثار بيسان التاريخية.']::text[], ARRAY['The Roman amphitheater.','Historic ruins of Bisan.']::text[], 'من الاسم الكنعاني "بيت شان".', 'From the Canaanite name "Beth Shan".', 'تُسمّى عبريًا "بيت شيان / ‎בית שאן".', 'Called "Beit She''an / ‎בית שאן" in Hebrew.', 'بيسان مدينة الأغوار المهجّرة وأحد أقدم مدن الأرض.', 'Bisan, the depopulated city of the Jordan Valley and one of the oldest cities on earth.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2c/Bet_Shean_Roman_theater.jpg/1280px-Bet_Shean_Roman_theater.jpg', ARRAY[]::text[], '2 يونيو 2026', 'June 2, 2026', 8)
insert into public.articles (id, title, title_en, excerpt, excerpt_en, date, date_en, image, category, author, author_en, reading_time, body, body_en, sort_order) values
  ('ard-almoqawama', 'لوحة فنية بعنوان "أرض المقاومة"', 'An artwork titled "Land of Resistance"', 'حكاية حبيبة، الطفلة التي رسمت أحلامها على قماش المخيم بألوان الأمل والصمود.', 'The story of Habiba, the child who painted her dreams on the camp''s canvas in colors of hope and steadfastness.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/cc/Children_of_Gaza_painting.jpg/1280px-Children_of_Gaza_painting.jpg', 'dreams', 'هيئة التحرير', 'Editorial team', 6, '[{"heading":"هل ترى ما أرى؟","paragraph":"دخان كثيف، عربات إسعاف، أشلاء تحت الأنقاض، ثلاجة آيس كريم تحولت إلى ثلاجة لحفظ الموتى بسبب انقطاع الكهرباء المستمر عن سكان قطاع غزة."},{"heading":"نعم!","paragraph":"لا يوجد سوى المستشفيات. تذهب الأمهات بأطفالها لتحتمي داخل تلك المستشفيات، لربما تكون سفينة النجاة في بحر الدماء."},{"paragraph":"في منتصف الليل تبدأ أجساد الأطفال المرتعدة من هول ما حدث في أحضان أمهاتها، بينما هناك طفل في آخر الرواق يحتضن الخواء فلم يتبق أحد من عائلته."},{"heading":"نحكي لكم عن \"حبيبة\"","paragraph":"إحدى أطفال المخيمات التي اضطرت عائلتها إلى اللجوء إليها بعد تهجيرهم من ديارهم الأصلية. كانت المخيمات عالم حبيبة الصغير الذي رسمت فيه أول لوحاتها الزاهية \"أنا أحب فلسطين\"."}]'::jsonb, '[{"heading":"Do you see what I see?","paragraph":"Thick smoke, ambulances, body parts under the rubble, an ice-cream freezer turned into a morgue because of the constant blackouts in the Gaza Strip."},{"heading":"Yes!","paragraph":"Nothing remains but the hospitals. Mothers carry their children inside, hoping the wards will be a lifeboat in a sea of blood."},{"paragraph":"At midnight, children''s bodies tremble from the horror in their mothers'' arms — while at the end of the corridor a child holds nothing but emptiness; not one member of his family remains."},{"heading":"Let us tell you about \"Habiba\"","paragraph":"A girl from one of the camps her family fled to after being displaced. The camps were Habiba''s small world — there she painted her first bright canvas: \"I love Palestine\"."}]'::jsonb, 0),
  ('salam-mafqoud', 'قصة: من حملة السلم الفارغ للمفقودة', 'A Story: from the empty-ladder campaign to the missing', 'رحلة بحث طويلة لعائلة فلسطينية تبحث عن أبنائها المفقودين في زحام الحرب.', 'A long journey for a Palestinian family searching for their children lost in the chaos of war.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/03/Palestinian_refugees.jpg/1280px-Palestinian_refugees.jpg', 'dreams', 'هيئة التحرير', 'Editorial team', 8, '[{"heading":"هل ترى ما أرى؟","paragraph":"دخان كثيف، عربات إسعاف، أشلاء تحت الأنقاض، ثلاجة آيس كريم تحولت إلى ثلاجة لحفظ الموتى بسبب انقطاع الكهرباء المستمر عن سكان قطاع غزة."},{"heading":"نعم!","paragraph":"لا يوجد سوى المستشفيات. تذهب الأمهات بأطفالها لتحتمي داخل تلك المستشفيات، لربما تكون سفينة النجاة في بحر الدماء."},{"paragraph":"في منتصف الليل تبدأ أجساد الأطفال المرتعدة من هول ما حدث في أحضان أمهاتها، بينما هناك طفل في آخر الرواق يحتضن الخواء فلم يتبق أحد من عائلته."},{"heading":"نحكي لكم عن \"حبيبة\"","paragraph":"إحدى أطفال المخيمات التي اضطرت عائلتها إلى اللجوء إليها بعد تهجيرهم من ديارهم الأصلية. كانت المخيمات عالم حبيبة الصغير الذي رسمت فيه أول لوحاتها الزاهية \"أنا أحب فلسطين\"."}]'::jsonb, '[{"heading":"Do you see what I see?","paragraph":"Thick smoke, ambulances, body parts under the rubble, an ice-cream freezer turned into a morgue because of the constant blackouts in the Gaza Strip."},{"heading":"Yes!","paragraph":"Nothing remains but the hospitals. Mothers carry their children inside, hoping the wards will be a lifeboat in a sea of blood."},{"paragraph":"At midnight, children''s bodies tremble from the horror in their mothers'' arms — while at the end of the corridor a child holds nothing but emptiness; not one member of his family remains."},{"heading":"Let us tell you about \"Habiba\"","paragraph":"A girl from one of the camps her family fled to after being displaced. The camps were Habiba''s small world — there she painted her first bright canvas: \"I love Palestine\"."}]'::jsonb, 1),
  ('tifl-aouni', 'قصة الطفل عوني الدوس', 'The story of the child Aouni al-Dous', 'حكاية طفل فلسطيني تحوّل حلمه إلى نهج مقاومة بعد أن فقد عائلته في غارة على غزة.', 'A Palestinian child whose dream turned into a path of resistance after losing his family in a strike on Gaza.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4e/Gaza_destruction_2014.jpg/1280px-Gaza_destruction_2014.jpg', 'dreams', 'هيئة التحرير', 'Editorial team', 7, '[{"heading":"هل ترى ما أرى؟","paragraph":"دخان كثيف، عربات إسعاف، أشلاء تحت الأنقاض، ثلاجة آيس كريم تحولت إلى ثلاجة لحفظ الموتى بسبب انقطاع الكهرباء المستمر عن سكان قطاع غزة."},{"heading":"نعم!","paragraph":"لا يوجد سوى المستشفيات. تذهب الأمهات بأطفالها لتحتمي داخل تلك المستشفيات، لربما تكون سفينة النجاة في بحر الدماء."},{"paragraph":"في منتصف الليل تبدأ أجساد الأطفال المرتعدة من هول ما حدث في أحضان أمهاتها، بينما هناك طفل في آخر الرواق يحتضن الخواء فلم يتبق أحد من عائلته."},{"heading":"نحكي لكم عن \"حبيبة\"","paragraph":"إحدى أطفال المخيمات التي اضطرت عائلتها إلى اللجوء إليها بعد تهجيرهم من ديارهم الأصلية. كانت المخيمات عالم حبيبة الصغير الذي رسمت فيه أول لوحاتها الزاهية \"أنا أحب فلسطين\"."}]'::jsonb, '[{"heading":"Do you see what I see?","paragraph":"Thick smoke, ambulances, body parts under the rubble, an ice-cream freezer turned into a morgue because of the constant blackouts in the Gaza Strip."},{"heading":"Yes!","paragraph":"Nothing remains but the hospitals. Mothers carry their children inside, hoping the wards will be a lifeboat in a sea of blood."},{"paragraph":"At midnight, children''s bodies tremble from the horror in their mothers'' arms — while at the end of the corridor a child holds nothing but emptiness; not one member of his family remains."},{"heading":"Let us tell you about \"Habiba\"","paragraph":"A girl from one of the camps her family fled to after being displaced. The camps were Habiba''s small world — there she painted her first bright canvas: \"I love Palestine\"."}]'::jsonb, 2),
  ('ahlam-1', 'أحلام لن تتحقق', 'Dreams that won''t come true', 'حكايات أطفال غزة التي بقيت معلّقة في فضاء الحرب.', 'Stories of Gaza''s children, left suspended in the space of war.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5e/Gaza_City_at_night.jpg/1280px-Gaza_City_at_night.jpg', 'dreams', NULL, NULL, 5, '[{"heading":"هل ترى ما أرى؟","paragraph":"دخان كثيف، عربات إسعاف، أشلاء تحت الأنقاض، ثلاجة آيس كريم تحولت إلى ثلاجة لحفظ الموتى بسبب انقطاع الكهرباء المستمر عن سكان قطاع غزة."},{"heading":"نعم!","paragraph":"لا يوجد سوى المستشفيات. تذهب الأمهات بأطفالها لتحتمي داخل تلك المستشفيات، لربما تكون سفينة النجاة في بحر الدماء."},{"paragraph":"في منتصف الليل تبدأ أجساد الأطفال المرتعدة من هول ما حدث في أحضان أمهاتها، بينما هناك طفل في آخر الرواق يحتضن الخواء فلم يتبق أحد من عائلته."},{"heading":"نحكي لكم عن \"حبيبة\"","paragraph":"إحدى أطفال المخيمات التي اضطرت عائلتها إلى اللجوء إليها بعد تهجيرهم من ديارهم الأصلية. كانت المخيمات عالم حبيبة الصغير الذي رسمت فيه أول لوحاتها الزاهية \"أنا أحب فلسطين\"."}]'::jsonb, '[{"heading":"Do you see what I see?","paragraph":"Thick smoke, ambulances, body parts under the rubble, an ice-cream freezer turned into a morgue because of the constant blackouts in the Gaza Strip."},{"heading":"Yes!","paragraph":"Nothing remains but the hospitals. Mothers carry their children inside, hoping the wards will be a lifeboat in a sea of blood."},{"paragraph":"At midnight, children''s bodies tremble from the horror in their mothers'' arms — while at the end of the corridor a child holds nothing but emptiness; not one member of his family remains."},{"heading":"Let us tell you about \"Habiba\"","paragraph":"A girl from one of the camps her family fled to after being displaced. The camps were Habiba''s small world — there she painted her first bright canvas: \"I love Palestine\"."}]'::jsonb, 3),
  ('ahlam-2', 'ما لا تعرفه عن فلسطين', 'What you don''t know about Palestine', 'فلسطين هي المنطقة الواقعة جنوب غرب آسيا، في الجزء الجنوبي من بلاد الشام.', 'Palestine is the region located in southwest Asia, in the southern part of the Levant.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a4/Palestine_landscape.jpg/1280px-Palestine_landscape.jpg', 'dreams', NULL, NULL, 4, '[{"heading":"هل ترى ما أرى؟","paragraph":"دخان كثيف، عربات إسعاف، أشلاء تحت الأنقاض، ثلاجة آيس كريم تحولت إلى ثلاجة لحفظ الموتى بسبب انقطاع الكهرباء المستمر عن سكان قطاع غزة."},{"heading":"نعم!","paragraph":"لا يوجد سوى المستشفيات. تذهب الأمهات بأطفالها لتحتمي داخل تلك المستشفيات، لربما تكون سفينة النجاة في بحر الدماء."},{"paragraph":"في منتصف الليل تبدأ أجساد الأطفال المرتعدة من هول ما حدث في أحضان أمهاتها، بينما هناك طفل في آخر الرواق يحتضن الخواء فلم يتبق أحد من عائلته."},{"heading":"نحكي لكم عن \"حبيبة\"","paragraph":"إحدى أطفال المخيمات التي اضطرت عائلتها إلى اللجوء إليها بعد تهجيرهم من ديارهم الأصلية. كانت المخيمات عالم حبيبة الصغير الذي رسمت فيه أول لوحاتها الزاهية \"أنا أحب فلسطين\"."}]'::jsonb, '[{"heading":"Do you see what I see?","paragraph":"Thick smoke, ambulances, body parts under the rubble, an ice-cream freezer turned into a morgue because of the constant blackouts in the Gaza Strip."},{"heading":"Yes!","paragraph":"Nothing remains but the hospitals. Mothers carry their children inside, hoping the wards will be a lifeboat in a sea of blood."},{"paragraph":"At midnight, children''s bodies tremble from the horror in their mothers'' arms — while at the end of the corridor a child holds nothing but emptiness; not one member of his family remains."},{"heading":"Let us tell you about \"Habiba\"","paragraph":"A girl from one of the camps her family fled to after being displaced. The camps were Habiba''s small world — there she painted her first bright canvas: \"I love Palestine\"."}]'::jsonb, 4),
  ('ahlam-3', 'قصة الطفل عوني الدوس - تتمة', 'The story of Aouni al-Dous — continued', 'تتمة لحكاية الطفل عوني ومسيرته بين الركام.', 'A continuation of Aouni''s story and his journey through the rubble.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/Gaza_children.jpg/1280px-Gaza_children.jpg', 'dreams', NULL, NULL, 6, '[{"heading":"هل ترى ما أرى؟","paragraph":"دخان كثيف، عربات إسعاف، أشلاء تحت الأنقاض، ثلاجة آيس كريم تحولت إلى ثلاجة لحفظ الموتى بسبب انقطاع الكهرباء المستمر عن سكان قطاع غزة."},{"heading":"نعم!","paragraph":"لا يوجد سوى المستشفيات. تذهب الأمهات بأطفالها لتحتمي داخل تلك المستشفيات، لربما تكون سفينة النجاة في بحر الدماء."},{"paragraph":"في منتصف الليل تبدأ أجساد الأطفال المرتعدة من هول ما حدث في أحضان أمهاتها، بينما هناك طفل في آخر الرواق يحتضن الخواء فلم يتبق أحد من عائلته."},{"heading":"نحكي لكم عن \"حبيبة\"","paragraph":"إحدى أطفال المخيمات التي اضطرت عائلتها إلى اللجوء إليها بعد تهجيرهم من ديارهم الأصلية. كانت المخيمات عالم حبيبة الصغير الذي رسمت فيه أول لوحاتها الزاهية \"أنا أحب فلسطين\"."}]'::jsonb, '[{"heading":"Do you see what I see?","paragraph":"Thick smoke, ambulances, body parts under the rubble, an ice-cream freezer turned into a morgue because of the constant blackouts in the Gaza Strip."},{"heading":"Yes!","paragraph":"Nothing remains but the hospitals. Mothers carry their children inside, hoping the wards will be a lifeboat in a sea of blood."},{"paragraph":"At midnight, children''s bodies tremble from the horror in their mothers'' arms — while at the end of the corridor a child holds nothing but emptiness; not one member of his family remains."},{"heading":"Let us tell you about \"Habiba\"","paragraph":"A girl from one of the camps her family fled to after being displaced. The camps were Habiba''s small world — there she painted her first bright canvas: \"I love Palestine\"."}]'::jsonb, 5),
  ('aqsa-1', 'كيف يصل الاحتلال للصوت الزائف للشفاء؟', 'How does the occupation reach the false narrative of Al-Shifa?', 'تحقيق حول استهداف مستشفى الشفاء في غزة وتداعياته الإنسانية.', 'An investigation into the targeting of Al-Shifa hospital in Gaza and its humanitarian consequences.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/95/Al-Shifa_hospital.jpg/1280px-Al-Shifa_hospital.jpg', 'alaqsa', NULL, NULL, 9, '[{"paragraph":"في السابع من أكتوبر 2023، انطلقت معركة طوفان الأقصى لتشكّل نقطة تحوّل في الصراع الفلسطيني-الإسرائيلي وفي وعي الأمة كافة."},{"heading":"الأقصى يُنادي","paragraph":"المسجد الأقصى المبارك أولى القبلتين وثالث الحرمين الشريفين، رمزٌ يحمل في طياته قرونًا من القداسة والإيمان."},{"paragraph":"تواجه فلسطين بعد الطوفان حملة عسكرية غير مسبوقة في قسوتها وامتدادها الزمني، استشهد فيها عشرات الآلاف من المدنيين."},{"heading":"صمود الناس","paragraph":"رغم كل ما جرى ويجري، تبقى إرادة الشعب الفلسطيني عصيّة على الكسر."}]'::jsonb, '[{"paragraph":"On October 7, 2023, the Al-Aqsa Flood operation began — a turning point in the Palestinian–Israeli conflict and in the consciousness of the whole region."},{"heading":"Al-Aqsa calls","paragraph":"The blessed Al-Aqsa Mosque, first of the two qiblas and third of the holy sanctuaries, is a symbol carrying centuries of sanctity and faith."},{"paragraph":"After the Flood, Palestine faces an unprecedented military campaign in its cruelty and duration, in which tens of thousands of civilians have been killed."},{"heading":"The people''s steadfastness","paragraph":"Despite everything that has happened and is still happening, the Palestinian people''s will remains unbreakable."}]'::jsonb, 6),
  ('aqsa-2', 'فلسطين عبر الزمان', 'Palestine through time', 'رحلة في تاريخ فلسطين من الكنعانيين حتى اليوم.', 'A journey through Palestine''s history from the Canaanites to today.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4c/Palestine_history.jpg/1280px-Palestine_history.jpg', 'alaqsa', NULL, NULL, 10, '[{"paragraph":"في السابع من أكتوبر 2023، انطلقت معركة طوفان الأقصى لتشكّل نقطة تحوّل في الصراع الفلسطيني-الإسرائيلي وفي وعي الأمة كافة."},{"heading":"الأقصى يُنادي","paragraph":"المسجد الأقصى المبارك أولى القبلتين وثالث الحرمين الشريفين، رمزٌ يحمل في طياته قرونًا من القداسة والإيمان."},{"paragraph":"تواجه فلسطين بعد الطوفان حملة عسكرية غير مسبوقة في قسوتها وامتدادها الزمني، استشهد فيها عشرات الآلاف من المدنيين."},{"heading":"صمود الناس","paragraph":"رغم كل ما جرى ويجري، تبقى إرادة الشعب الفلسطيني عصيّة على الكسر."}]'::jsonb, '[{"paragraph":"On October 7, 2023, the Al-Aqsa Flood operation began — a turning point in the Palestinian–Israeli conflict and in the consciousness of the whole region."},{"heading":"Al-Aqsa calls","paragraph":"The blessed Al-Aqsa Mosque, first of the two qiblas and third of the holy sanctuaries, is a symbol carrying centuries of sanctity and faith."},{"paragraph":"After the Flood, Palestine faces an unprecedented military campaign in its cruelty and duration, in which tens of thousands of civilians have been killed."},{"heading":"The people''s steadfastness","paragraph":"Despite everything that has happened and is still happening, the Palestinian people''s will remains unbreakable."}]'::jsonb, 7),
  ('aqsa-3', 'تغطية مستشفى المعمداني', 'Coverage of the Baptist Hospital', 'تفاصيل حول مجزرة المستشفى المعمداني في غزة.', 'Details of the Baptist Hospital massacre in Gaza.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2e/Baptist_Hospital_Gaza.jpg/1280px-Baptist_Hospital_Gaza.jpg', 'alaqsa', NULL, NULL, 7, '[{"paragraph":"في السابع من أكتوبر 2023، انطلقت معركة طوفان الأقصى لتشكّل نقطة تحوّل في الصراع الفلسطيني-الإسرائيلي وفي وعي الأمة كافة."},{"heading":"الأقصى يُنادي","paragraph":"المسجد الأقصى المبارك أولى القبلتين وثالث الحرمين الشريفين، رمزٌ يحمل في طياته قرونًا من القداسة والإيمان."},{"paragraph":"تواجه فلسطين بعد الطوفان حملة عسكرية غير مسبوقة في قسوتها وامتدادها الزمني، استشهد فيها عشرات الآلاف من المدنيين."},{"heading":"صمود الناس","paragraph":"رغم كل ما جرى ويجري، تبقى إرادة الشعب الفلسطيني عصيّة على الكسر."}]'::jsonb, '[{"paragraph":"On October 7, 2023, the Al-Aqsa Flood operation began — a turning point in the Palestinian–Israeli conflict and in the consciousness of the whole region."},{"heading":"Al-Aqsa calls","paragraph":"The blessed Al-Aqsa Mosque, first of the two qiblas and third of the holy sanctuaries, is a symbol carrying centuries of sanctity and faith."},{"paragraph":"After the Flood, Palestine faces an unprecedented military campaign in its cruelty and duration, in which tens of thousands of civilians have been killed."},{"heading":"The people''s steadfastness","paragraph":"Despite everything that has happened and is still happening, the Palestinian people''s will remains unbreakable."}]'::jsonb, 8),
  ('aqsa-4', 'مجزرة مدرسة الفاخورة', 'The Al-Fakhoura school massacre', 'وثائق وشهادات عن استهداف مدرسة الفاخورة في جباليا.', 'Documents and testimonies on the targeting of Al-Fakhoura school in Jabalia.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6d/UNRWA_school.jpg/1280px-UNRWA_school.jpg', 'alaqsa', NULL, NULL, 8, '[{"paragraph":"في السابع من أكتوبر 2023، انطلقت معركة طوفان الأقصى لتشكّل نقطة تحوّل في الصراع الفلسطيني-الإسرائيلي وفي وعي الأمة كافة."},{"heading":"الأقصى يُنادي","paragraph":"المسجد الأقصى المبارك أولى القبلتين وثالث الحرمين الشريفين، رمزٌ يحمل في طياته قرونًا من القداسة والإيمان."},{"paragraph":"تواجه فلسطين بعد الطوفان حملة عسكرية غير مسبوقة في قسوتها وامتدادها الزمني، استشهد فيها عشرات الآلاف من المدنيين."},{"heading":"صمود الناس","paragraph":"رغم كل ما جرى ويجري، تبقى إرادة الشعب الفلسطيني عصيّة على الكسر."}]'::jsonb, '[{"paragraph":"On October 7, 2023, the Al-Aqsa Flood operation began — a turning point in the Palestinian–Israeli conflict and in the consciousness of the whole region."},{"heading":"Al-Aqsa calls","paragraph":"The blessed Al-Aqsa Mosque, first of the two qiblas and third of the holy sanctuaries, is a symbol carrying centuries of sanctity and faith."},{"paragraph":"After the Flood, Palestine faces an unprecedented military campaign in its cruelty and duration, in which tens of thousands of civilians have been killed."},{"heading":"The people''s steadfastness","paragraph":"Despite everything that has happened and is still happening, the Palestinian people''s will remains unbreakable."}]'::jsonb, 9),
  ('aqsa-5', 'اتفاق الهدنة بغزة 2023', 'The Gaza truce agreement, 2023', 'تحليل لبنود الهدنة المؤقتة في نوفمبر 2023.', 'An analysis of the November 2023 temporary truce terms.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/1f/Gaza_ceasefire.jpg/1280px-Gaza_ceasefire.jpg', 'alaqsa', NULL, NULL, 6, '[{"paragraph":"في السابع من أكتوبر 2023، انطلقت معركة طوفان الأقصى لتشكّل نقطة تحوّل في الصراع الفلسطيني-الإسرائيلي وفي وعي الأمة كافة."},{"heading":"الأقصى يُنادي","paragraph":"المسجد الأقصى المبارك أولى القبلتين وثالث الحرمين الشريفين، رمزٌ يحمل في طياته قرونًا من القداسة والإيمان."},{"paragraph":"تواجه فلسطين بعد الطوفان حملة عسكرية غير مسبوقة في قسوتها وامتدادها الزمني، استشهد فيها عشرات الآلاف من المدنيين."},{"heading":"صمود الناس","paragraph":"رغم كل ما جرى ويجري، تبقى إرادة الشعب الفلسطيني عصيّة على الكسر."}]'::jsonb, '[{"paragraph":"On October 7, 2023, the Al-Aqsa Flood operation began — a turning point in the Palestinian–Israeli conflict and in the consciousness of the whole region."},{"heading":"Al-Aqsa calls","paragraph":"The blessed Al-Aqsa Mosque, first of the two qiblas and third of the holy sanctuaries, is a symbol carrying centuries of sanctity and faith."},{"paragraph":"After the Flood, Palestine faces an unprecedented military campaign in its cruelty and duration, in which tens of thousands of civilians have been killed."},{"heading":"The people''s steadfastness","paragraph":"Despite everything that has happened and is still happening, the Palestinian people''s will remains unbreakable."}]'::jsonb, 10),
  ('aqsa-6', 'مجزرة الشفاء', 'The Al-Shifa massacre', 'ما جرى في مستشفى الشفاء من تدمير ممنهج.', 'The systematic destruction that took place at Al-Shifa hospital.', '2 يونيو 2026', 'June 2, 2026', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3d/Gaza_Strip_destruction.jpg/1280px-Gaza_Strip_destruction.jpg', 'alaqsa', NULL, NULL, 7, '[{"paragraph":"في السابع من أكتوبر 2023، انطلقت معركة طوفان الأقصى لتشكّل نقطة تحوّل في الصراع الفلسطيني-الإسرائيلي وفي وعي الأمة كافة."},{"heading":"الأقصى يُنادي","paragraph":"المسجد الأقصى المبارك أولى القبلتين وثالث الحرمين الشريفين، رمزٌ يحمل في طياته قرونًا من القداسة والإيمان."},{"paragraph":"تواجه فلسطين بعد الطوفان حملة عسكرية غير مسبوقة في قسوتها وامتدادها الزمني، استشهد فيها عشرات الآلاف من المدنيين."},{"heading":"صمود الناس","paragraph":"رغم كل ما جرى ويجري، تبقى إرادة الشعب الفلسطيني عصيّة على الكسر."}]'::jsonb, '[{"paragraph":"On October 7, 2023, the Al-Aqsa Flood operation began — a turning point in the Palestinian–Israeli conflict and in the consciousness of the whole region."},{"heading":"Al-Aqsa calls","paragraph":"The blessed Al-Aqsa Mosque, first of the two qiblas and third of the holy sanctuaries, is a symbol carrying centuries of sanctity and faith."},{"paragraph":"After the Flood, Palestine faces an unprecedented military campaign in its cruelty and duration, in which tens of thousands of civilians have been killed."},{"heading":"The people''s steadfastness","paragraph":"Despite everything that has happened and is still happening, the Palestinian people''s will remains unbreakable."}]'::jsonb, 11)
insert into public.figures (id, name, name_en, birth_year, death_year, birth_city, field, bio, bio_en, portrait, sort_order) values
  ('yasser-arafat', 'ياسر عرفات', 'Yasser Arafat', 1929, 2004, 'al-quds', 'politics', 'أبو عمار، رئيس منظمة التحرير الفلسطينية وأول رئيس للسلطة الوطنية الفلسطينية. قاد النضال الفلسطيني لعقود وحاز جائزة نوبل للسلام عام 1994.', 'Abu Ammar, chairman of the PLO and first president of the Palestinian Authority. He led the Palestinian struggle for decades and was awarded the Nobel Peace Prize in 1994.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Yasser_Arafat_in_DC.jpg/640px-Yasser_Arafat_in_DC.jpg', 0),
  ('mahmoud-darwish', 'محمود درويش', 'Mahmoud Darwish', 1941, 2008, 'haifa', 'literature', 'شاعر فلسطين الأكبر، صاحب "سجل أنا عربي" و"على هذه الأرض ما يستحق الحياة". صوت الذاكرة الفلسطينية والهوية في الشعر العربي الحديث.', 'Palestine''s greatest poet, author of "Record! I am an Arab" and "On this earth, that which is worthy of life" — the voice of Palestinian memory and identity in modern Arabic poetry.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/95/Mahmoud_Darwish.jpg/640px-Mahmoud_Darwish.jpg', 1),
  ('ghassan-kanafani', 'غسان كنفاني', 'Ghassan Kanafani', 1936, 1972, 'yaffa', 'literature', 'روائي وصحفي فلسطيني، صاحب "رجال في الشمس" و"عائد إلى حيفا". اغتاله الموساد في بيروت عام 1972.', 'A Palestinian novelist and journalist, author of "Men in the Sun" and "Returning to Haifa". Assassinated by the Mossad in Beirut in 1972.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3b/Ghassan_Kanafani.jpg/640px-Ghassan_Kanafani.jpg', 2),
  ('edward-said', 'إدوارد سعيد', 'Edward Said', 1935, 2003, 'al-quds', 'science', 'مفكر ومنظّر فلسطيني-أمريكي، صاحب كتاب "الاستشراق" الذي غيّر دراسات ما بعد الكولونيالية.', 'A Palestinian–American intellectual and theorist, author of "Orientalism", a book that transformed post-colonial studies.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/05/Edward_Said_-_2.jpg/640px-Edward_Said_-_2.jpg', 3),
  ('naji-alali', 'ناجي العلي', 'Naji al-Ali', 1938, 1987, NULL, 'arts', 'رسام الكاريكاتير الفلسطيني الأشهر، خالق شخصية "حنظلة" التي صارت رمزًا للقضية. اغتيل في لندن عام 1987.', 'Palestine''s most famous cartoonist, creator of the character "Handala" who became a symbol of the cause. Assassinated in London in 1987.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3a/Handala.svg/640px-Handala.svg.png', 4),
  ('fadwa-touqan', 'فدوى طوقان', 'Fadwa Tuqan', 1917, 2003, 'nablus', 'literature', 'شاعرة فلسطين الأم، رائدة الشعر العربي الحديث وصوت الأرض المحتلة.', 'Palestine''s mother poet, a pioneer of modern Arabic poetry and the voice of the occupied land.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6b/Fadwa_Tuqan.jpg/640px-Fadwa_Tuqan.jpg', 5),
  ('izz-aldin-alqassam', 'عز الدين القسّام', 'Izz ad-Din al-Qassam', 1882, 1935, NULL, 'resistance', 'شيخ ومقاوم فلسطيني سوري الأصل، قاد المقاومة المسلحة ضد الانتداب البريطاني واستشهد عام 1935.', 'A Palestinian-Syrian sheikh and resistance fighter who led armed resistance against the British Mandate and was martyred in 1935.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c0/Sheikh_Izz_ad-Din_al-Qassam.jpg/640px-Sheikh_Izz_ad-Din_al-Qassam.jpg', 6),
  ('leila-khaled', 'ليلى خالد', 'Leila Khaled', 1944, NULL, 'haifa', 'resistance', 'مناضلة فلسطينية ورمز نضالي للمرأة الفلسطينية، عضوة في الجبهة الشعبية لتحرير فلسطين.', 'A Palestinian fighter and an icon of Palestinian women''s struggle, a member of the Popular Front for the Liberation of Palestine.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8f/Leila_Khaled_2009.jpg/640px-Leila_Khaled_2009.jpg', 7)
insert into public.history_events (id, title, title_en, event_date, event_date_en, iso_date, event_type, description, description_en, image, related_city, sources, sources_en, sort_order) values
  ('balfour-1917', 'وعد بلفور', 'The Balfour Declaration', '2 نوفمبر 1917', 'November 2, 1917', '1917-11-02', 'milestone', 'تصريح وزير الخارجية البريطاني آرثر بلفور بمنح اليهود "وطنًا قوميًا" في فلسطين، وهو أول وثيقة دولية فتحت الطريق لمشروع الاستيطان الصهيوني.', 'The British Foreign Secretary Arthur Balfour''s declaration granting Jews a "national home" in Palestine — the first international document to pave the way for the Zionist settlement project.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4b/Balfour_declaration_unmarked.jpg/1280px-Balfour_declaration_unmarked.jpg', NULL, ARRAY['الأرشيف البريطاني الوطني']::text[], ARRAY['The British National Archives']::text[], 0),
  ('nakba-1948', 'النكبة الفلسطينية', 'The Palestinian Nakba', '15 مايو 1948', 'May 15, 1948', '1948-05-15', 'nakba', 'تهجير أكثر من 750 ألف فلسطيني من ديارهم وتدمير أكثر من 530 قرية ومدينة، وإعلان قيام الكيان الصهيوني على الأرض الفلسطينية.', 'The displacement of more than 750,000 Palestinians from their homes and the destruction of over 530 villages and cities, and the declaration of the Zionist entity on Palestinian land.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Palestinian_refugees.jpg/1280px-Palestinian_refugees.jpg', 'yaffa', ARRAY[]::text[], ARRAY[]::text[], 1),
  ('naksa-1967', 'النكسة وحرب 1967', 'The Naksa and the 1967 War', '5 يونيو 1967', 'June 5, 1967', '1967-06-05', 'war', 'احتلال إسرائيل للضفة الغربية وقطاع غزة والقدس الشرقية والجولان وسيناء في حرب الأيام الستة.', 'Israel''s occupation of the West Bank, Gaza Strip, East Jerusalem, the Golan, and Sinai in the Six-Day War.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4d/Six_Day_War_Territories.svg/1280px-Six_Day_War_Territories.svg.png', NULL, ARRAY[]::text[], ARRAY[]::text[], 2),
  ('intifada-1987', 'الانتفاضة الفلسطينية الأولى', 'The First Palestinian Intifada', '8 ديسمبر 1987', 'December 8, 1987', '1987-12-08', 'uprising', 'انتفاضة شعبية شاملة في الضفة الغربية وقطاع غزة، عُرفت بانتفاضة الحجارة، وأعادت القضية الفلسطينية إلى الواجهة الدولية.', 'A comprehensive popular uprising in the West Bank and Gaza known as the Stone Intifada, which brought the Palestinian cause back to international attention.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2e/First_intifada.jpg/1280px-First_intifada.jpg', NULL, ARRAY[]::text[], ARRAY[]::text[], 3),
  ('oslo-1993', 'اتفاق أوسلو', 'The Oslo Accords', '13 سبتمبر 1993', 'September 13, 1993', '1993-09-13', 'milestone', 'توقيع اتفاق إعلان المبادئ بين منظمة التحرير الفلسطينية وإسرائيل في البيت الأبيض.', 'Signing of the Declaration of Principles between the PLO and Israel at the White House.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7a/Bill_Clinton%2C_Yitzhak_Rabin%2C_Yasser_Arafat_at_the_White_House_1993-09-13.jpg/1280px-Bill_Clinton%2C_Yitzhak_Rabin%2C_Yasser_Arafat_at_the_White_House_1993-09-13.jpg', NULL, ARRAY[]::text[], ARRAY[]::text[], 4),
  ('aqsa-intifada-2000', 'انتفاضة الأقصى', 'The Al-Aqsa Intifada', '28 سبتمبر 2000', 'September 28, 2000', '2000-09-28', 'uprising', 'انطلقت بعد اقتحام أرييل شارون للمسجد الأقصى، واستمرت خمس سنوات سقط فيها آلاف الشهداء.', 'Triggered by Ariel Sharon''s storming of the Al-Aqsa Mosque, it lasted five years and saw thousands killed.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/08/Al-Aqsa_Mosque_view.jpg/1280px-Al-Aqsa_Mosque_view.jpg', 'al-quds', ARRAY[]::text[], ARRAY[]::text[], 5),
  ('tufan-alaqsa-2023', 'طوفان الأقصى', 'Al-Aqsa Flood', '7 أكتوبر 2023', 'October 7, 2023', '2023-10-07', 'war', 'عملية كبرى أطلقتها المقاومة الفلسطينية من غزة، تبعها عدوان إسرائيلي واسع على القطاع.', 'A major operation launched by the Palestinian resistance from Gaza, followed by a wide-scale Israeli assault on the Strip.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3d/Gaza_Strip_destruction.jpg/1280px-Gaza_Strip_destruction.jpg', 'ghazza', ARRAY[]::text[], ARRAY[]::text[], 6)
